const items = $input.first().json.data.items;
const actionable = items.filter(item => item.status === 'In Progress' || item.status === 'Ready');
if (actionable.length === 0) return [];
// Prioritize: In Progress first, then by priority descending
actionable.sort((a, b) => {
  if (a.status === 'In Progress' && b.status !== 'In Progress') return -1;
  if (b.status === 'In Progress' && a.status !== 'In Progress') return 1;
  return (b.meta?.priority || 0) - (a.meta?.priority || 0);
});
// Take only the first item (Moe handles one at a time)
return [{ json: { item: actionable[0], project_fields: $input.first().json.data.project_fields } }];
